exercise3.solutionCode:
def create_schedule():
    return [("Python Basics", "Room A"), ("Data Lab", "Room B"), ("Web Starter", "Room C")]

def build_room_lookup(schedule):
    return {name: room for name, room in schedule}

def format_schedule(schedule):
    return [f"{name} — {room}" for name, room in schedule]
